2.3 Conditional Statements

2.3.1 If Statements
The simplest form of conditional execution:

x &lt;- 10

if (x &gt; 5) {
  print("x is greater than 5")
}

[1] "x is greater than 5"

# Multiple conditions
y &lt;- 3
if (x &gt; 5 & y &lt; 5) {
  print("Both conditions are true")
}

[1] "Both conditions are true"




2.3.2 If-Else Statements
Execute different code blocks based on conditions:

score &lt;- 75

if (score &gt;= 90) {
  grade &lt;- "A"
} else if (score &gt;= 80) {
  grade &lt;- "B"
} else if (score &gt;= 70) {
  grade &lt;- "C"
} else if (score &gt;= 60) {
  grade &lt;- "D"
} else {
  grade &lt;- "F"
}

print(paste("Grade:", grade))

[1] "Grade: C"




2.3.3 The ifelse() Function
Vectorized version for element-wise conditional assignment:

ages &lt;- c(15, 22, 17, 30, 16, 45)

# Classify as "adult" or "minor"
status &lt;- ifelse(ages &gt;= 18, "adult", "minor")
status

[1] "minor" "adult" "minor" "adult" "minor" "adult"

# Nested ifelse
scores &lt;- c(55, 72, 88, 95, 60, 45)
result &lt;- ifelse(scores &gt;= 90, "Excellent",
            ifelse(scores &gt;= 70, "Good",
            ifelse(scores &gt;= 50, "Pass", "Fail")))
result

[1] "Pass"      "Good"      "Good"      "Excellent" "Pass"      "Fail"

2.6 Practical Examples

2.6.1 Example 1: Calculating π using Buffon’s Needle
Buffons needle problem estimates π by dropping needles on a lined surface:

buffon_needle &lt;- function(n_trials, needle_length = 1, line_spacing = 1) {
  # Generate random needle positions and angles
  y_center &lt;- runif(n_trials, 0, line_spacing / 2)
  angle &lt;- runif(n_trials, 0, pi / 2)

  # Check if needle crosses a line
  y_tip &lt;- y_center + (needle_length / 2) * sin(angle)
  crosses &lt;- y_tip &gt;= line_spacing / 2

  # Estimate pi
  pi_estimate &lt;- (2 * needle_length * n_trials) / (line_spacing * sum(crosses))
  return(pi_estimate)
}

set.seed(123)
# Run simulation with different numbers of trials
trials &lt;- c(100, 1000, 10000)
for (n in trials) {
  estimate &lt;- buffon_needle(n)
  print(paste("Trials:", n, "- π estimate:", round(estimate, 4)))
}

[1] "Trials: 100 - π estimate: 2.9412"
[1] "Trials: 1000 - π estimate: 3.1496"
[1] "Trials: 10000 - π estimate: 3.1852"




2.6.2 Example 2: Factorial Function

# Recursive factorial
factorial_recursive &lt;- function(n) {
  if (n &lt;= 1) {
    return(1)
  } else {
    return(n * factorial_recursive(n - 1))
  }
}

# Iterative factorial
factorial_iterative &lt;- function(n) {
  result &lt;- 1
  for (i in 2:n) {
    result &lt;- result * i
  }
  return(result)
}

# Compare
factorial_recursive(5)

[1] 120

factorial_iterative(5)

[1] 120




2.6.3 Example 3: Monte Carlo Integration

# Estimate integral of f(x) from a to b using Monte Carlo
mc_integrate &lt;- function(f, a, b, n = 10000) {
  # Generate random points
  x &lt;- runif(n, a, b)

  # Evaluate function
  fx &lt;- f(x)

  # Monte Carlo estimate
  integral &lt;- (b - a) * mean(fx)
  return(integral)
}

# Example: integrate x^2 from 0 to 1 (true value = 1/3)
f &lt;- function(x) x^2
estimate &lt;- mc_integrate(f, 0, 1, n = 100000)
print(paste("Monte Carlo estimate:", estimate))

[1] "Monte Carlo estimate: 0.333438419856698"

print(paste("True value:", 1/3))

[1] "True value: 0.333333333333333"




2.6.4 Example 4: Newton-Raphson Method

# Find root of f(x) = 0 using Newton-Raphson
newton_raphson &lt;- function(f, df, x0, tolerance = 1e-6, max_iter = 100) {
  x &lt;- x0
  for (i in 1:max_iter) {
    fx &lt;- f(x)
    if (abs(fx) &lt; tolerance) {
      return(list(root = x, iterations = i))
    }
    dfx &lt;- df(x)
    if (abs(dfx) &lt; 1e-10) {
      stop("Derivative too small")
    }
    x &lt;- x - fx / dfx
  }
  stop("Maximum iterations reached")
}

# Example: Find sqrt(2) by solving x^2 - 2 = 0
f &lt;- function(x) x^2 - 2
df &lt;- function(x) 2 * x

result &lt;- newton_raphson(f, df, x0 = 1)
print(paste("Square root of 2:", result$root))

[1] "Square root of 2: 1.41421356237469"

print(paste("Iterations:", result$iterations))

[1] "Iterations: 5"

